var duplicateZeros = function(arr) {
    const n = arr.length;
    let zeros = 0;
    for (const v of arr) if (v === 0) zeros++;
    let i = n - 1, j = n + zeros - 1;
    while (i >= 0) {
        if (j < n) arr[j] = arr[i];
        if (arr[i] === 0) {
            j--;
            if (j < n) arr[j] = 0;
        }
        i--;
        j--;
    }
};
